// Extract user data from Clerk webhook payload
const payload = $input.all()[0].json;

// Clerk sends nested data structure
const userData = payload.data || payload;
const email = userData.email_addresses?.[0]?.email_address || userData.email || 'user@example.com';
const firstName = userData.first_name || 'there';
const role = userData.public_metadata?.role || userData.role || 'student';

return [{
  json: {
    email: email,
    firstName: firstName,
    role: role
  }
}];

